  ('disabled-64311456-moex-00024', 'disabled-64311456', 'disabled-64311456-moex-114-decd973b', 'sub-disabled-64311456-01', NULL, 'single_choice', '民法第195條第3項規定，不法侵害他人基於子女關係之身分法益而情節 重大者，得請求賠償相當之金額。關於本條規定解釋上是否包含養子女之 爭議，若法官參酌民法第 1077 條第 1 項，「養子女與養父母及其親屬間 之關係，除法律另有規定外，與婚生子女同」之規定，而認及於養子女。 法官採取下列何種解釋方法？', '["主觀解釋", "合憲性解釋", "歷史解釋", "體系解釋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
